#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define N 500005
#define INF 0x3f3f3f3f 
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9'){if(ch=='-')flag=1;ch=getchar();}
	while(ch<='9'&&ch>='0')res=(res<<1)+(res<<3)+(ch^48),ch=getchar();
	return flag?-res:res;
}
int n,m,Root,T1,T2,T3;
int stk[500010],top=0;
struct node
{
	int siz,key,tag,l,r; bool rev;
	struct Data
	{
		int sum,lmx,rmx,nmx;
		Data friend operator + (Data x,Data y)
		{
			return (Data){x.sum+y.sum,max(x.sum+y.lmx,x.lmx),max(y.sum+x.rmx,y.rmx),max(max(x.nmx,y.nmx),x.rmx+y.lmx)};
		}
	}data,val;
}t[500010],lit;
int newNode(int x)
{
	int now=stk[top--];
	if(t[now].l) stk[++top]=t[now].l;
	if(t[now].r) stk[++top]=t[now].r; 
	t[now].data=t[now].val={x,x,x,x};
	t[now].siz=1;
	t[now].l=t[now].r=t[now].rev=0;t[now].tag=INF;
	return now;
}
void update(int x)
{
	if(!x) return;
	t[x].siz=t[t[x].l].siz+1+t[t[x].r].siz;
	t[x].data=t[x].val;
	if(t[x].l) t[x].data=t[t[x].l].data+t[x].data;
	if(t[x].r) t[x].data=t[x].data+t[t[x].r].data;
}
void Cnt(int now,int x)
{
	t[now].val={x,x,x,x};
	t[now].tag=x;
	t[now].data={t[now].val.sum*t[now].siz,max(0,t[now].val.sum*t[now].siz),max(0,t[now].val.sum*t[now].siz),t[now].val.sum*t[now].siz};
}
void Rev(int x)
{
	swap(t[x].l,t[x].r); swap(t[x].data.lmx,t[x].data.rmx); t[x].rev^=1;
}
void pushdown(int x)
{
	if(!x) return;
	if(t[x].tag!=INF)
	{
		Cnt(t[x].l,t[x].tag);
		Cnt(t[x].r,t[x].tag);
		t[x].tag=INF;
	}
	if(t[x].rev)
	{
		if(t[x].l) Rev(t[x].l);
		if(t[x].r) Rev(t[x].r);
		t[x].rev=0;
	}
}
inline void split(int k,int cur,int &x,int &y)
{
	if(!cur){x=y=0;return;}pushdown(cur);
	if(t[t[cur].l].siz>=k)y=cur,split(k,t[cur].l,x,t[cur].l);
	else x=cur,split(k-t[t[cur].l].siz-1,t[cur].r,t[cur].r,y);
	update(cur); return;
}
inline int merge(int x,int y)
{
	if(!x||!y)return x|y;
	pushdown(x);pushdown(y);
	if(rand()%(t[x].siz+t[y].siz)<t[x].siz)
	{
		t[x].r=merge(t[x].r,y);
		update(x);return x;
	}
	t[y].l=merge(x,t[y].l);
	update(y);return y;
}
inline void ins(int p,int tot)
{
	split(p,Root,T1,T2);
	rep(1,tot,i)T1=merge(T1,newNode(read()));
	Root=merge(T1,T2);
}
inline void del(int p,int tot)
{
	split(p-1,Root,T1,T2);split(tot,T2,T2,T3);
	if(top<N-1)stk[++top]=T2;Root=merge(T1,T3);
}
inline void Fix(int p,int tot)
{
	split(p-1,Root,T1,T2);split(tot,T2,T2,T3);
	Cnt(T2,read());
	Root=merge(merge(T1,T2),T3);
}
inline void Reve(int p,int tot)
{
	split(p-1,Root,T1,T2);split(tot,T2,T2,T3);
	Rev(T2);Root=merge(merge(T1,T2),T3);
}
inline void Sum(int p,int tot)
{
	split(p-1,Root,T1,T2);split(tot,T2,T2,T3);
	printf("%d\n",t[T2].data.sum);Root=merge(merge(T1,T2),T3);
}
int main()
{
//	freopen("in.txt","r",stdin);
	srand((unsigned long long)(-1));
	std::ios::sync_with_stdio(false);
	n=read(); m=read(); char opt[9];
	rep(1,500000,i)stk[++top]=i;
	rep(1,n,i) Root=merge(Root,newNode(read()));
	int p,T;rep(1,m,i){scanf("%s",opt);switch(opt[2])
	{
		case 'S': p=read();T=read();ins(p,T);break;
		case 'L': p=read();T=read();del(p,T);break;
		case 'K': p=read();T=read();Fix(p,T);break;
		case 'V': p=read();T=read();Reve(p,T);break;
		case 'T': p=read();T=read();Sum(p,T);break;
		case 'X': printf("%d\n",t[Root].data.nmx);break;
	}}
}
